#include<stdio.h>
int main()
{
    int i,t,j,a[100],n,s=0;
    scanf("%d",&n);
    for(i=1;i<=n;i++)
    scanf("%d",&a[i]);
    for(i=1;i<=n;i++)
    for(j=1;j<=n-i;j++)
    {
        if(a[j]>a[j+1])
        {
            t=a[j];
            a[j]=a[j+1];
            a[j+1]=t;
        }
    }

    for(i=1;i<n;i+=2)
    s=s+a[i+1]-a[i];
    printf("%d",s);
  return 0;
}

