fn main() {
    let mut stdin = String::new();
    std::io::Read::read_to_string(
        &mut std::io::stdin(),
        &mut stdin).unwrap();
    let mut stdin = stdin.split_whitespace();
    let mut get = || stdin.next().unwrap();
    macro_rules! get {
        ($t:ty) => (get().parse::<$t>().unwrap());
        () => (get!(i64));
    }

    let n = get!(usize);
    let mut xs = vec![];
    for _ in 0..n {
        let x = get!();
        xs.push(x);
    }
    xs.sort();
    let mut ans = 0;
    for i in 0..n/2 {
        ans += xs[i*2+1]-xs[i*2];
    }
    println!("{}", ans);
}
